/** Free/Pro/Max access is derived from each mock's existing `tier`/`isFree` fields and each
 * note's `isFree` field, rather than hand-maintained id lists, so newly added mocks/notes are
 * automatically covered without editing PRODUCT_PLANS every time the catalog grows. */
const PUBLISHED_MOCKS = MOCKS.filter((mock) => mock.published);
const FREE_MOCK_IDS = PUBLISHED_MOCKS.filter((mock) => mock.isFree).map((mock) => mock.id);
const PRO_MOCK_IDS = PUBLISHED_MOCKS.filter((mock) => mock.tier !== "Elite").map((mock) => mock.id);
const MAX_MOCK_IDS = PUBLISHED_MOCKS.map((mock) => mock.id);

const FREE_NOTE_IDS = NOTE_PAGES.filter((note) => note.isFree).map((note) => note.id);
const ALL_NOTE_IDS = NOTE_PAGES.map((note) => note.id);

